SELECT *
FROM parking_spots
WHERE capacity = (SELECT MAX(capacity) FROM parking_spots);

SELECT spot_id
FROM parking_spots
WHERE capacity = (
  SELECT MAX(capacity)
  FROM parking_spots
);

SELECT COUNT(DISTINCT user_id) AS unique_users
FROM access_logs
WHERE access_date = '2023-05-01';

SELECT MIN(access_time) AS earliest_access_time
FROM access_logs
WHERE access_date = (
  SELECT MIN(access_date) AS earliest_date
  FROM access_logs
);

SELECT lat, lng
FROM parking_spots
WHERE campus = 'UTSG';

SELECT COUNT(spot_id) AS total_bicycle_spots
FROM parking_spots
WHERE type = 'bicycle' AND campus = 'UTSG';

SELECT COUNT(*) 
FROM parking_spots 
WHERE campus = 'UTSC';
